pub use api_asscrack;

// Browser-only: installs a wasm SQLite VFS backed by browser storage, then
// runs a trivial query through it. `install_opfs_sahpool`'s SAH-pool VFS
// needs `createSyncAccessHandle`, which requires a cross-origin-isolated
// page (COOP/COEP) that the plain wasm-pack test harness does not serve, so
// this instead exercises `install_relaxed_idb` (IndexedDB-backed, no
// cross-origin isolation needed) directly against `rusqlite::Connection` —
// the production path (`impl_rusqulite::_new_connection`) always opens the
// SAH-pool VFS and isn't exercised here.
#[cfg(all(test, target_arch = "wasm32"))]
mod tests {
    use wasm_bindgen_test::wasm_bindgen_test;

    wasm_bindgen_test::wasm_bindgen_test_configure!(run_in_browser);

    #[wasm_bindgen_test]
    async fn smoke_relaxed_idb_migrate_and_query() {
        crate::install_relaxed_idb()
            .await
            .expect("install_relaxed_idb");

        let conn = rusqlite::Connection::open("file:crackhouse_smoke.db?vfs=relaxed-idb")
            .expect("open rusqlite connection over relaxed-idb VFS");
        conn.execute("CREATE TABLE IF NOT EXISTS smoke (id INTEGER PRIMARY KEY)", [])
            .expect("create table over relaxed-idb VFS");
        conn.execute("INSERT INTO smoke (id) VALUES (1)", [])
            .expect("insert over relaxed-idb VFS");
        let count: i64 = conn
            .query_row("SELECT COUNT(*) FROM smoke", [], |row| row.get(0))
            .expect("query over relaxed-idb VFS");
        assert_eq!(count, 1);
    }
}

use serde::{Deserialize, Serialize};

#[derive(Deserialize, Serialize, Clone, Debug)]
pub struct SQLAndParams {
    pub sql: String,
    pub params: Vec<DbValue>,
}

#[derive(Clone, Debug, PartialEq, Deserialize, Serialize)]
pub enum DbValueType {
    Null,
    Integer,
    Real,
    Text,
    Blob,
}

impl DbValueType {
    pub fn to_sql_str(&self) -> &'static str {
        match self {
            Self::Null => "NULL",
            Self::Integer => "Integer",
            Self::Real => "Real",
            Self::Text => "Text",
            Self::Blob => "Blob",
        }
    }
}

#[derive(Clone, Debug, PartialEq, Deserialize, Serialize)]
pub enum DbValue {
    /// The value is a `NULL` value.
    Null,
    /// The value is a signed integer.
    Integer(i64),
    /// The value is a floating point number.
    Real(f64),
    /// The value is a text string.
    Text(String),
    /// The value is a blob of data
    Blob(Vec<u8>),
}
impl DbValue {
    pub fn fold_option(value: Option<DbValue>) -> DbValue {
        match value {
            None => Self::Null,
            Some(v) => v,
        }
    }
}

impl From<i64> for DbValue {
    fn from(value: i64) -> Self {
        Self::Integer(value)
    }
}
impl From<String> for DbValue {
    fn from(value: String) -> Self {
        Self::Text(value)
    }
}
impl From<f64> for DbValue {
    fn from(value: f64) -> Self {
        Self::Real(value)
    }
}
impl From<Vec<u8>> for DbValue {
    fn from(value: Vec<u8>) -> Self {
        Self::Blob(value)
    }
}
impl<T> From<Option<T>> for DbValue
where
    DbValue: From<T>,
{
    fn from(value: Option<T>) -> Self {
        match value {
            None => Self::Null,
            Some(value) => DbValue::from(value),
        }
    }
}

impl TryFrom<DbValue> for i64 {
    type Error = anyhow::Error;
    fn try_from(value: DbValue) -> Result<i64, Self::Error> {
        match value {
            DbValue::Integer(value) => Ok(value),
            _ => anyhow::bail!("cannot convert"),
        }
    }
}

impl TryFrom<DbValue> for f64 {
    type Error = anyhow::Error;
    fn try_from(value: DbValue) -> Result<f64, Self::Error> {
        match value {
            DbValue::Real(value) => Ok(value),
            _ => anyhow::bail!("cannot convert"),
        }
    }
}

impl TryFrom<DbValue> for String {
    type Error = anyhow::Error;
    fn try_from(value: DbValue) -> Result<String, Self::Error> {
        match value {
            DbValue::Text(value) => Ok(value),
            _ => anyhow::bail!("cannot convert"),
        }
    }
}

impl TryFrom<DbValue> for Vec<u8> {
    type Error = anyhow::Error;
    fn try_from(value: DbValue) -> Result<Vec<u8>, Self::Error> {
        match value {
            DbValue::Blob(value) => Ok(value),
            _ => anyhow::bail!("cannot convert"),
        }
    }
}

trait DbPrimitive {}
impl DbPrimitive for String {}
impl DbPrimitive for i64 {}
impl DbPrimitive for f64 {}
impl DbPrimitive for Vec<u8> {}

impl<T> TryFrom<DbValue> for Option<T>
where
    T: TryFrom<DbValue> + DbPrimitive,
{
    type Error = anyhow::Error;

    fn try_from(value: DbValue) -> Result<Option<T>, Self::Error> {
        match value {
            DbValue::Null => Ok(None),
            _z => DbValue::try_into(_z),
        }
    }
}

impl From<rusqlite::types::Value> for DbValue {
    fn from(value: rusqlite::types::Value) -> Self {
        match value {
            rusqlite::types::Value::Null => DbValue::Null,
            rusqlite::types::Value::Integer(a) => DbValue::Integer(a),
            rusqlite::types::Value::Real(a) => DbValue::Real(a),
            rusqlite::types::Value::Text(a) => DbValue::Text(a),
            rusqlite::types::Value::Blob(a) => DbValue::Blob(a),
        }
    }
}
impl From<DbValue> for rusqlite::types::Value {
    fn from(value: DbValue) -> Self {
        match value {
            DbValue::Null => rusqlite::types::Value::Null,
            DbValue::Integer(a) => rusqlite::types::Value::Integer(a),
            DbValue::Real(a) => rusqlite::types::Value::Real(a),
            DbValue::Text(a) => rusqlite::types::Value::Text(a),
            DbValue::Blob(a) => rusqlite::types::Value::Blob(a),
        }
    }
}

